import{_ as e}from"./chunks/文件受限图.DsG20F9s.js";import{_ as o,o as r,c as t,a2 as i}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"Moderação de imagens e modo de acesso","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Safety/image-moderation-and-access-mode.md","filePath":"pt-BR/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),d={name:"pt-BR/Safety/image-moderation-and-access-mode.md"};function s(c,a,n,l,m,u){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="moderacao-de-imagens-e-modo-de-acesso" tabindex="-1">Moderação de imagens e modo de acesso <a class="header-anchor" href="#moderacao-de-imagens-e-modo-de-acesso" aria-label="Permalink to &quot;Moderação de imagens e modo de acesso&quot;">​</a></h1><p>Moderação de imagens e modo de acesso controlam quais arquivos visitantes podem ver, com base em regras públicas, listas e classificação etária.</p><p>Eles funcionam junto com galeria pública, API de imagem aleatória e acesso externo a arquivos.</p><h2 id="o-que-da-para-fazer" tabindex="-1">O que dá para fazer <a class="header-anchor" href="#o-que-da-para-fazer" aria-label="Permalink to &quot;O que dá para fazer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Recurso</th><th>Descrição</th></tr></thead><tbody><tr><td>Moderação de imagens</td><td>Registrar informações de conteúdo ou classificação</td></tr><tr><td>Lista negra</td><td>Excluir arquivos que não devem ser públicos</td></tr><tr><td>Modo lista branca</td><td>Publicar apenas arquivos permitidos explicitamente</td></tr><tr><td>Controle por idade</td><td>Ajustar visibilidade de R12, R16, R18 e similares</td></tr><tr><td>Modo de acesso</td><td>Alterar globalmente o que visitantes podem ver</td></tr></tbody></table><h2 id="modo-de-acesso" tabindex="-1">Modo de acesso <a class="header-anchor" href="#modo-de-acesso" aria-label="Permalink to &quot;Modo de acesso&quot;">​</a></h2><p>O modo de acesso limita o que páginas públicas e API aleatória podem retornar.</p><p>Se você quer um site adequado para todo público, configure para retornar apenas arquivos gerais. Para uso interno ou acesso restrito, ajuste regras mais flexíveis conforme a necessidade.</p><h2 id="arquivo-restrito" tabindex="-1">Arquivo restrito <a class="header-anchor" href="#arquivo-restrito" aria-label="Permalink to &quot;Arquivo restrito&quot;">​</a></h2><p>Quando um arquivo é restrito, o visitante vê um aviso em vez do conteúdo original.</p><p><img src="'+e+'" alt="Arquivo restrito" loading="lazy"></p><h2 id="formas-de-operacao" tabindex="-1">Formas de operação <a class="header-anchor" href="#formas-de-operacao" aria-label="Permalink to &quot;Formas de operação&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Abordagem</th><th>Quando usar</th></tr></thead><tbody><tr><td>Lista negra</td><td>Publicar por padrão e excluir arquivos problemáticos</td></tr><tr><td>Lista branca</td><td>Publicar apenas o que foi revisado e permitido</td></tr><tr><td>Classificação por idade</td><td>Alterar visibilidade conforme o nível do conteúdo</td></tr></tbody></table><p>Para sites públicos, lista branca ou classificação por idade ajudam a evitar publicação indevida.</p><h2 id="o-que-conferir" tabindex="-1">O que conferir <a class="header-anchor" href="#o-que-conferir" aria-label="Permalink to &quot;O que conferir&quot;">​</a></h2><ol><li>Veja se o arquivo aparece na galeria pública.</li><li>Confira se a API aleatória não retorna arquivos restritos.</li><li>Após mudar listas, considere cache ou resultados já gerados.</li><li>Se usar classificação automática, revise manualmente arquivos sensíveis porque modelos podem errar.</li></ol>',16)])])}const b=o(d,[["render",s]]);export{q as __pageData,b as default};
